SELECT 
FROM social_friend_request
WHERE from_user_id = #{fromUserId}
  AND to_user_id = #{toUserId}
  AND status = 'PENDING'
LIMIT 1

SELECT COUNT(1)
FROM social_friend_request
WHERE from_user_id = #{fromUserId}
  AND to_user_id = #{toUserId}
  AND created_at >= DATE_SUB(CURRENT_TIMESTAMP(3), INTERVAL 24 HOUR)
